Here is the code that simulates the RDD spliter and print the errors (Language: C).
You can get some numbers of your log (like 995741 and 5000 in the example above), prepare your dataset files(images and labels), compile this code, then use:
`./(exe) (your_feature_file) (your_labels_file) (feature_output_file_1) (feature_output_file_2) (label_output_file_1) (label_output_file_2) (feature_file_split_position) (label_file_split_position) (batch_size)`
like my example:
`./exe feature label f_split_1 f_split_2 l_split_1 l_split_2 995741 5000 100`

```
#include<stdio.h>
#include<sys/stat.h>
unsigned long get_file_size(const char *path)  
{  
    unsigned long filesize = -1;      
    struct stat statbuff;  
    if(stat(path, &statbuff) < 0){  
        return filesize;  
    }else{  
        filesize = statbuff.st_size;  
    }  
    return filesize;  
}  
unsigned long strToInt(char *s){
	int i=0;
	unsigned long res=0;
	while(s[i]!=0){
		res*=10;
		res+=s[i]-48;
		i++;
	}
	return res;
}
void split(int res[2], char *input, char *output_1, char *output_2, unsigned long len, unsigned long batch_size){
	FILE *f=fopen(input,"r");
	FILE *wf1=fopen(output_1,"w");
	FILE *wf2=fopen(output_2,"w");
	int i = 0;
	int count=0;
	char s[2]={0};
	while(1){
		fseek(f, i, SEEK_SET);
		fread(s, 1, 1, f);
		if(s[0]==10){
			count++;
			i+=2;
			fprintf(wf1,"%c",s[0]);
			if(i>len)break;
			continue;
		}
		fprintf(wf1,"%c",s[0]);
		i++;
		if(i>=len)break;
	}
	res[0]=(count+1)%batch_size;
	count=0;
	while(1){
		fseek(f, i, SEEK_SET);
		fread(s, 1, 1, f);
		if(s[0]==10){
			count++;
			i+=2;
			fprintf(wf2,"%c",s[0]);
			if(i>=get_file_size(input))break;
			continue;
		}
		fprintf(wf2,"%c",s[0]);
		i++;
		if(i>get_file_size(input))break;
	}
	res[1]=(count-1+batch_size)%batch_size;
	fclose(f);
	fclose(wf1);
	fclose(wf2);
}
int main(int argc, char **argv){
	if(argc<10){
		printf("you should input more than 9 parameters.\nUsage: NAME F_input L_input F_output1 F_output2 L_output1 L_output2 F_split_pos L_split_pos batch_size \n");
		printf("NAME: This executors file name\n");
		printf("F_input: The features(images) input file name\n");
		printf("L_input: The labels input file name\n");
		printf("F_output1: The first output file name for features(images)\n");
		printf("F_output2: The second output file name for features(images)\n");
		printf("L_output1: The first output file name for labels\n");
		printf("L_output2: The second output file name for labels\n");
		printf("F_split_pos: The position(bytes) of feature(image) file that you want to split by (if the original file is x bytes, then file C will contains the first E bytes, D will contains the rest\n");
		printf("L_split_pos: The position(bytes) of label file that you want to split by\n");
		printf("batch_size: The size of each batch (is set on your tensorflow code, default is 100)\n");
		return 0;
	}
	int feat[2], lab[2];
	split(feat, argv[1], argv[3], argv[4], strToInt(argv[7]), strToInt(argv[9]));
	split(lab, argv[2], argv[5], argv[6], strToInt(argv[8]), strToInt(argv[9]));
	printf("The error message of ValueError may be:\n");
	printf("ValueError: Can not deserialize PairRDD with different number of items in batches: (%d, %d)\n", feat[0], lab[0]);
	printf("and\n");
	printf("ValueError: Can not deserialize PairRDD with different number of items in batches: (%d, %d)\n", feat[1], lab[1]);
	return 0;
}
```
