import docker


class DryRunClient(docker.Client):
    def request(self, method, url, params=None, data=None, headers=None,
                *args, **kwargs):
        return {
            'method': method,
            'url': url,
            'params': params,
            'data': data,
            'headers': headers
        }

    def _result(self, response, *args, **kwargs):
        return response

    def _raise_for_status(self, *args, **kwargs):
        pass

    def _stream_helper(self, response, *args, **kwargs):
        return response

    def _get_result(self, container, stream, response):
        return response

    def _get_result_tty(self, stream, response, is_tty):
        return response
```

